// Competency: httpsts-worked-http-server-ts-fields-representations-cache-4.
// Case 1655: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: abort during a dependency phase and preserve cleanup plus response ownership.
function worked_http_server_ts_fields_representations_cache_4(acceptJson: boolean, etagMatches: boolean, privateData: boolean): { status: number; cacheControl: string; vary: string } {
  if (!acceptJson) return { status: 406, cacheControl: "no-store", vary: "Accept" };
  const cacheControl = privateData ? "private, no-store" : "public, max-age=60";
  const status = etagMatches ? 304 : 200;
  return { status, cacheControl, vary: "Accept, Accept-Encoding" };
}

